={{ JSON.stringify({
  model: "gpt-4o-mini",
  messages: [
    {
      role: "system",
      content: "Você é a IA 1 (Classificador) da escola Décia. Seu único objetivo é classificar a intenção e o risco das mensagens recebidas e retornar estritamente um JSON.

Campos no JSON:
- intent: 'JUSTIFICATIVA_FALTA' (se o responsável justifica faltas ou atrasos), 'DUVIDA_SECRETARIA' (dúvidas sobre horários, secretaria, documentos, matrículas), 'HUMANO' (solicitação explícita de falar com humano), ou 'DESCONHECIDO' (outros assuntos ou conversa fiada).
- category: 'DOENCA', 'TRABALHO', 'TRANSPORTE', 'FAMILIA', 'OUTRO' (se intent for JUSTIFICATIVA_FALTA), ou null caso contrário.
- risk_level: 'LOW' (baixo risco), 'MEDIUM' (desânimo, recorrência moderada), 'HIGH' (bullying, conflitos graves, problemas jurídicos, ameaças, agressividade, saúde mental grave).
- needs_human: true (se risk_level for HIGH, se houver agressividade/bullying, solicitação explícita ou tom conflituoso), ou false caso contrário.
- confidence: float entre 0.0 e 1.0 (grau de certeza na classificação).

Regra de Ouro: Retorne APENAS o JSON. Não adicione texto explicativo ou markdown."
    },
    {
      role: "user",
      content: "Contexto:
- Aluno: " + ($node["GET Session Context"].json.student_name || "não identificado") + "
- Último Motivo: " + ($node["GET Session Context"].json.last_reason || "não informado") + "
- Campanha: " + ($node["GET Session Context"].json.campaign_name || "não informado") + "
- Dias Falta: " + ($node["GET Session Context"].json.campaign_absence_days || "não informado") + "

Histórico Recente:
" + JSON.stringify($node["GET Session Context"].json.messages || [], null, 2) + "

Mensagem Atual: " + ($node["Webhook Chat"].json.message_text || $node["Webhook Chat"].json.body?.message_text || "") + "

Retorne agora a classificação JSON estrita."
    }
  ],
  response_format: { type: "json_object" }
}) }}

parameters.jsCode:
let response = {
  intent: "DESCONHECIDO",
  category: null,
  risk_level: "LOW",
  needs_human: true,
  confidence: 0.0,
  needs_review: true,
  handoff_reason: "erro_classificacao"
};

try {
  let content = $json.choices[0].message.content.trim();
  if (content.startsWith("```json")) {
    content = content.substring(7);
  }
  if (content.endsWith("```")) {
    content = content.substring(0, content.length - 3);
  }
  let parsed = JSON.parse(content.trim());

  response.intent = parsed.intent || "DESCONHECIDO";
  response.category = parsed.category || null;
  response.risk_level = parsed.risk_level || "LOW";
  response.needs_human = parsed.needs_human === true || parsed.needs_human === "true";
  response.confidence = parseFloat(parsed.confidence) || 0.0;
  response.needs_review = response.needs_human;

  // Se a confiança for menor que 0.75, força handoff humano
  if (response.confidence < 0.75) {
    response.needs_human = true;
    response.needs_review = true;
    response.handoff_reason = "baixa_confianca";
  } else if (response.needs_human) {
    response.handoff_reason = parsed.category || "detectado_ia";
  }
} catch (e) {
  response.needs_human = true;
  response.needs_review = true;
  response.handoff_reason = "erro_json_parse";
}

return response;

let input = $json;
return {
  response_text: "Agradecemos sua mensagem. Nossa equipe registrou as informações e seguirá acompanhando o caso.",
  model: "static_handoff",
  prompt_version: "v1",
  detected_intent: input.intent || "HUMANO",
  risk_level: input.risk_level || "LOW",
  handoff_reason: input.handoff_reason || "detectado_ia"
};

